import json
from lfx.custom import Component
from lfx.inputs.inputs import MessageTextInput
from lfx.io import Output
from lfx.schema.data import Data


class ToolCallingAgentComponent_0002(Component):
    """Synthetic data capability for Test Case Assignment System. Returns realistic generated sample data
    instead of calling a real API, so the agent can be tested end-to-end before the real
    system is connected. Swap to a real connector later by providing the API details."""

    display_name = "Test Case Assignment"
    description = "Returns synthetic/test data for Test Case Assignment System (no real API call). Provide 'payload' with the request fields."
    icon = "TestTube"
    name = "ToolCallingAgentComponent_0002"

    inputs = [
        MessageTextInput(name="payload", display_name="Request Payload",
                         info="The request fields (JSON). Echoed back in the synthetic response.",
                         value="{}", required=False, tool_mode=True),
        MessageTextInput(name="sample_response", display_name="Sample Response (JSON)",
                         info="The synthetic response template returned to the agent.",
                         value="{\"status\": \"Active\", \"assignment_id\": \"ASSIGN-50234\", \"test_case_id\": \"TC-100524\", \"assigned_to\": {\"name\": \"Sarah Johnson\", \"email\": \"qa_engineer@company.com\", \"role\": \"Senior QA Engineer\", \"current_workload\": \"4 active assignments\"}, \"assignment_date\": \"2026-03-06T14:35:00Z\", \"due_date\": \"2026-03-10T17:00:00Z\", \"execution_environment\": \"Staging\", \"estimated_completion\": \"2026-03-09T10:00:00Z\", \"notification_sent\": true, \"message\": \"Test case successfully assigned to Sarah Johnson. Notification sent.\"}", required=False),
    ]

    outputs = [
        Output(name="result", display_name="Result", method="call_api", tool_mode=True),
    ]

    def call_api(self) -> Data:
        try:
            try:
                sent = json.loads(getattr(self, "payload", "") or "{}")
            except Exception:
                sent = {}
            try:
                sample = json.loads(getattr(self, "sample_response", "") or "{}")
            except Exception:
                sample = {}
            # Merge submitted fields into the sample so the response reflects the input.
            if isinstance(sample, dict):
                merged = dict(sample)
                if isinstance(sent, dict):
                    for k, v in sent.items():
                        merged.setdefault(k, v)
                result = {"capability": "Test Case Assignment", "status": "completed",
                          "synthetic": True, "result": merged}
            else:
                result = {"capability": "Test Case Assignment", "status": "completed",
                          "synthetic": True, "result": sample}
        except Exception as e:
            result = {"capability": "Test Case Assignment", "status": "error", "synthetic": True, "error": str(e)}
        self.status = result
        return Data(data=result)
